-- REGULIS — Real Estate Disclosure Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- Transfer Disclosure Statement (TDS)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_128', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1102-1102.17 (Transfer Disclosure Statement)', 'CC §§ 1102-1102.17', 'Transfer Disclosure Statement — Residential Property Sale', 'Seller of residential real property (1-4 units) must provide buyer with a Transfer Disclosure Statement (TDS) disclosing all known material facts affecting value or desirability of the property. Seller completes two sections: items on the property and seller''s awareness of defects. Seller''s agent must conduct a reasonably competent visual inspection and disclose findings. Buyer has 3 days (in person) or 5 days (by mail) to rescind after receipt. TDS is the cornerstone of California residential disclosure law.', '["Seller must disclose all known material facts affecting value or desirability","TDS required for 1-4 unit residential property transfers","Seller completes Section I (items/equipment) and Section II (known conditions)","Seller agent must conduct reasonably competent visual inspection","Seller agent discloses findings in Section III","Buyer agent discloses findings in Section IV","Buyer right to rescind: 3 days in person, 5 days by mail after delivery","Exemptions: court-ordered sales, foreclosure, fiduciary sales, new construction (first sale)","Good faith required — no liability for unknown defects if good faith disclosure","Amended TDS required if seller discovers new material facts before close"]', '[{"section":"1102","description":"Legislative intent and scope of disclosure requirements"},{"section":"1102.1","description":"Definitions — transfer, real property, agent"},{"section":"1102.3","description":"Exemptions — court orders, foreclosure, fiduciary, probate"},{"section":"1102.4","description":"Errors in disclosure — good faith standard, no liability for unknown"},{"section":"1102.6","description":"TDS form — statutory form content requirements"},{"section":"1102.7","description":"Delivery requirements — 3 day/5 day rescission right"},{"section":"1102.9","description":"Seller agent visual inspection duty"},{"section":"1102.13","description":"Amendment obligation — material changes before close"},{"section":"1102.17","description":"Applicability to all residential 1-4 unit transfers"}]', '["transfer_disclosure_statement","property_inspection_report","seller_questionnaire","agent_visual_inspection","rescission_notice","amended_disclosure","purchase_agreement_disclosure_addendum"]', '["california-real-estate-audit"]', 'California DRE / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Natural Hazard Disclosure (NHD)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_129', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1103-1103.14 (Natural Hazard Disclosure)', 'CC §§ 1103-1103.14', 'Natural Hazard Disclosure Statement — Residential Property Sale', 'Seller or seller''s agent must disclose whether residential property (1-4 units) is located within any of six statutorily defined natural hazard areas. Disclosure must be made using the statutory Natural Hazard Disclosure Statement (NHDS) form. Seller may use a third-party NHD report from a qualified expert to fulfill disclosure obligation. Six hazard zones: special flood hazard area (FEMA), dam inundation, very high fire hazard severity zone, wildland fire area, earthquake fault zone, seismic hazard zone.', '["Must disclose if property is in special flood hazard area (FEMA Zone A/V)","Must disclose if property is in area of potential dam inundation","Must disclose if property is in very high fire hazard severity zone (PRC 4125)","Must disclose if property is in wildland area that may contain substantial fire risks (PRC 4126)","Must disclose if property is in earthquake fault zone (Alquist-Priolo)","Must disclose if property is in seismic hazard zone (liquefaction, landslide)","Statutory NHDS form required","Third-party expert report may substitute for seller/agent research","Expert report provides good faith immunity to seller and agent","Buyer right to rescind: 3 days in person, 5 days by mail"]', '[{"section":"1103","description":"Legislative declaration — natural hazard disclosure policy"},{"section":"1103.1","description":"Scope — applies to 1-4 unit residential transfers"},{"section":"1103.2","description":"Six natural hazard zones requiring disclosure"},{"section":"1103.3","description":"Exemptions — same as TDS exemptions"},{"section":"1103.4","description":"Third-party expert report — good faith immunity"},{"section":"1103.5","description":"NHDS statutory form content"},{"section":"1103.7","description":"Delivery and rescission timing"},{"section":"1103.8","description":"Local hazard disclosure not preempted"},{"section":"1103.14","description":"Errors or inaccuracies — good faith defense"}]', '["natural_hazard_disclosure_statement","NHD_expert_report","flood_zone_determination","fire_hazard_zone_map","earthquake_fault_zone_map","seismic_hazard_zone_map","dam_inundation_map","rescission_notice"]', '["california-real-estate-audit"]', 'California DRE / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Mello-Roos / Special Tax District Disclosure
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_130', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1102.6b / Cal. Gov. Code § 53341.5 (Mello-Roos Community Facilities Act Disclosure)', 'CC § 1102.6b / GC § 53341.5', 'Mello-Roos / Special Tax District Disclosure — Residential Property Sale', 'Seller of residential property within a Mello-Roos Community Facilities District (CFD) must provide buyer written notice of the special tax lien. Mello-Roos districts levy special taxes to fund infrastructure (roads, schools, utilities) in new developments. The special tax is in addition to regular ad valorem property taxes and is not deductible as a property tax for federal purposes. Buyer must receive notice before transfer of title. Failure to disclose may allow buyer to rescind.', '["Seller must provide written notice that property is subject to Mello-Roos special tax lien","Notice required before transfer of title","Notice must include: CFD name/number, annual special tax amount, maximum special tax, expiration date of tax","Must disclose that special tax is in addition to regular property taxes","Must state whether special tax may be prepaid and at what cost","Buyer may rescind if not provided proper disclosure","Developer/subdivider disclosure required for new home sales (GC § 53341.5)","Escrow holder may not record transfer deed without evidence of disclosure compliance","Special tax lien has same priority as ad valorem property tax lien"]', '[{"section":"CC 1102.6b","description":"Seller disclosure obligation for Mello-Roos special tax"},{"section":"GC 53340","description":"Mello-Roos Community Facilities Act of 1982"},{"section":"GC 53341.5","description":"Developer disclosure requirements for new subdivisions"},{"section":"GC 53344","description":"Special tax lien — priority and enforcement"},{"section":"GC 53356","description":"Continuing disclosure — annual reporting requirements"},{"section":"GC 53359","description":"Judicial validation of CFD proceedings"}]', '["mello_roos_disclosure","special_tax_lien_notice","CFD_formation_documents","annual_special_tax_bill","prepayment_calculation","escrow_disclosure_compliance","subdivision_disclosure"]', '["california-real-estate-audit"]', 'California DRE / County Tax Collector / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Supplemental Property Tax Disclosure
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_131', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1102.6c (Supplemental Property Tax Notice)', 'CC § 1102.6c', 'Supplemental Property Tax Disclosure — Residential Property Sale', 'Seller must notify buyer that a supplemental property tax bill will be issued upon change of ownership, reflecting the difference between the prior assessed value and the new assessed value. Supplemental tax is prorated from date of ownership change to end of the fiscal year. Buyer may receive one or two supplemental tax bills depending on when the transfer occurs relative to the fiscal year (July 1 to June 30). This is separate from the annual property tax bill.', '["Seller must disclose that supplemental property tax bill will be issued upon change of ownership","Supplemental bill reflects difference between old and new assessed value","Prorated from date of ownership change to end of fiscal year","Buyer may receive one or two supplemental bills depending on timing","Supplemental tax is separate from and in addition to annual property tax","Disclosure typically included in TDS or as separate notice","Failure to disclose does not eliminate buyer obligation to pay","Notice should advise buyer to contact county assessor for estimated amount"]', '[{"section":"CC 1102.6c","description":"Supplemental property tax disclosure requirement"},{"section":"R&T 75","description":"Supplemental assessment on change of ownership"},{"section":"R&T 75.10","description":"Supplemental roll — date of assessment"},{"section":"R&T 75.12","description":"Proration of supplemental tax"},{"section":"R&T 75.31","description":"Supplemental tax billing and collection"}]', '["supplemental_tax_disclosure","TDS_supplement","supplemental_tax_estimate","change_of_ownership_statement","property_tax_proration"]', '["california-real-estate-audit"]', 'County Assessor / California DRE / Civil Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — HOA / Davis-Stirling Common Interest Development
-- ═══════════════════════════════════════════════════════════════════════════

-- Davis-Stirling Common Interest Development Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_132', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 4000-6150 (Davis-Stirling Common Interest Development Act)', 'CC §§ 4000-6150', 'Davis-Stirling Common Interest Development Act — HOA Governance', 'Comprehensive statute governing homeowners associations (HOAs) in California common interest developments (condominiums, planned developments, stock cooperatives, community apartment projects). Covers governance, meetings, elections, assessments, maintenance, insurance, dispute resolution, and owner rights. Effective January 1, 2014 (replaced former CC §§ 1350-1378). All HOAs must comply regardless of when the development was created.', '["HOA must be incorporated as nonprofit mutual benefit corporation","Board of directors governs HOA — fiduciary duty to members","Annual budget must be distributed to members 30-90 days before fiscal year","Reserve study required every 3 years — visual inspection component","Annual policy statement required (CC § 5310)","Open meeting requirements — members may attend board meetings","Secret ballot elections required for assessments, board elections, amendments","Records must be available for member inspection within specified timeframes","Architectural review standards must be published","Insurance requirements — common areas and directors/officers coverage"]', '[{"section":"4000-4080","description":"General provisions — definitions, applicability, delivery rules"},{"section":"4100-4190","description":"Creation and governance of CID — declaration, bylaws, articles"},{"section":"4200-4275","description":"Governing documents — amendment, restated documents"},{"section":"4340-4370","description":"Membership and voting rights — quorum, proxies, secret ballot"},{"section":"4500-4530","description":"Record inspection rights and disclosure requirements"},{"section":"4600-4650","description":"Common areas — transfer, partition, exclusive use"},{"section":"4700-4780","description":"Association governance — board meetings, open meeting act"},{"section":"4800-4855","description":"Elections — secret ballot, inspector of elections"},{"section":"5200-5240","description":"Budget and fiscal management — reserve funding"},{"section":"5300-5320","description":"Assessment obligations and limits"},{"section":"5600-5690","description":"Insurance and liability requirements"},{"section":"5700-5740","description":"Assessment collection and liens"},{"section":"5900-5965","description":"Dispute resolution — IDR and ADR"}]', '["CC_and_Rs","HOA_bylaws","HOA_articles_of_incorporation","annual_budget","reserve_study","annual_policy_statement","meeting_minutes","election_ballots","architectural_guidelines","insurance_certificate","member_records_request"]', '["california-real-estate-audit"]', 'California DRE / Bureau of Real Estate / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- HOA Disclosure Package — Resale
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_133', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 4525-4530 (HOA Resale Disclosure Package)', 'CC §§ 4525-4530', 'HOA Disclosure Package — Resale of Separate Interest', 'When a unit in a common interest development is sold, the HOA must provide a disclosure package to the prospective buyer upon request. Package includes CC&Rs, bylaws, operating rules, financial documents (budget, reserve study, financial statements), pending litigation disclosures, and assessment information. HOA must provide within 10 days of request. Seller must provide package to buyer; buyer has right to cancel purchase within specified period if not provided.', '["HOA must provide disclosure package within 10 days of written request","Package must include governing documents (CC&Rs, bylaws, articles, operating rules)","Must include most recent financial statement and annual budget report","Must include most recent reserve study","Must include statement of assessments — regular and special","Must include any pending or anticipated special assessments","Must include insurance summary (types, coverage, carrier)","Must include pending litigation statement","Must disclose any known defects in common areas","Must include age of major components from reserve study","Must include minutes of regular board meetings for prior 12 months","Buyer cancellation right if package not provided","Fee for disclosure package capped by statute"]', '[{"section":"4525","description":"Disclosure package contents — complete list of required documents"},{"section":"4525(a)(1)","description":"Governing documents — CC&Rs, bylaws, articles, operating rules"},{"section":"4525(a)(3)","description":"Financial documents — budget, reserves, assessment info"},{"section":"4525(a)(4)","description":"Insurance information — coverage summary"},{"section":"4525(a)(7)","description":"Pending litigation or claims disclosure"},{"section":"4528","description":"Statement of fees and charges"},{"section":"4530","description":"Form of delivery — electronic permitted if agreed"}]', '["HOA_disclosure_package","CC_and_Rs","HOA_bylaws","reserve_study","annual_budget","financial_statement","insurance_summary","pending_litigation_disclosure","assessment_statement","board_meeting_minutes","operating_rules"]', '["california-real-estate-audit"]', 'California DRE / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- HOA Assessment Collection / Lien
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_134', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 5700-5740 (HOA Assessment Collection and Lien Procedures)', 'CC §§ 5700-5740', 'HOA Assessment Collection and Lien Enforcement', 'Governs HOA procedures for collecting delinquent assessments and recording liens against member''s separate interest. HOA must follow strict procedural requirements before recording a lien or pursuing foreclosure. Assessment lien is prior to all liens except tax liens and first deeds of trust recorded before the assessment delinquency. Board must vote in open meeting before recording lien. Nonjudicial foreclosure prohibited for assessments under $1,800 (exclusive of fines, fees, costs) unless delinquent more than 12 months.', '["Pre-lien letter required at least 30 days before recording lien (CC § 5660)","Pre-lien letter must include amount owed, right to request IDR/ADR, right to review records","Board must approve lien by majority vote in open meeting","Lien must be recorded with county recorder","Assessment lien priority: after tax liens and prior first deeds of trust","Nonjudicial foreclosure prohibited if amount less than $1,800 (excluding fines/fees/costs)","Nonjudicial foreclosure prohibited if delinquent less than 12 months","Interest on delinquent assessments limited to 12% per annum","Late charges limited to 10% of delinquent assessment or $10, whichever is greater","HOA must offer payment plan before pursuing foreclosure on primary residence","Owner has 90-day right of redemption after nonjudicial foreclosure sale"]', '[{"section":"5650","description":"Assessment obligation — personal obligation and lien"},{"section":"5660","description":"Pre-lien notice requirements — 30-day notice"},{"section":"5673","description":"Priority of assessment lien"},{"section":"5700","description":"Decision to record lien — board vote in open meeting"},{"section":"5710","description":"Nonjudicial foreclosure — $1,800 threshold and 12-month rule"},{"section":"5715","description":"Nonjudicial foreclosure procedures"},{"section":"5720","description":"Payment plan requirement before foreclosure on primary residence"},{"section":"5725","description":"Right of redemption — 90 days after foreclosure sale"},{"section":"5730","description":"Limitation on fees and costs — must be reasonable"},{"section":"5740","description":"Collection practices — Rosenthal Act applies to HOA"}]', '["pre_lien_notice","lien_recording","delinquent_assessment_statement","payment_plan_agreement","foreclosure_notice","right_of_redemption_notice","board_lien_approval_minutes","assessment_demand","collection_policy"]', '["california-real-estate-audit"]', 'California Civil Courts / DRE', 1, 1, datetime('now'), datetime('now'));

-- HOA Dispute Resolution — IDR and ADR
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_135', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 5900-5965 (HOA Dispute Resolution — IDR and ADR)', 'CC §§ 5900-5965', 'HOA Dispute Resolution — Internal Dispute Resolution and Alternative Dispute Resolution', 'Davis-Stirling Act establishes a two-tier dispute resolution framework for HOA disputes. Internal Dispute Resolution (IDR) is a meet-and-confer process between the member and HOA board. Alternative Dispute Resolution (ADR) includes mediation and arbitration. HOA must offer IDR before filing or pursuing litigation against a member. Failure to participate in ADR before filing civil action may result in losing right to recover attorney fees even if prevailing. Annual policy statement must describe IDR and ADR procedures.', '["HOA must provide IDR procedure — meet and confer between member and board","Either party may request IDR — meeting within 15 days of request","IDR meeting location: reasonable, agreed upon or within development","Board must designate member of board to meet with requesting member","ADR includes mediation and arbitration — voluntary unless CC&Rs require","Party refusing ADR before litigation may lose right to attorney fees (CC § 5960)","ADR applies to disputes involving enforcement of governing documents","ADR applies to disputes regarding member discipline and assessment disputes","Court may order parties to ADR before trial","Annual policy statement must include IDR and ADR procedures (CC § 5310)","Prevailing party attorney fees available under CC § 5975 if ADR attempted"]', '[{"section":"5900","description":"Internal dispute resolution — procedure requirements"},{"section":"5905","description":"IDR request — meeting within 15 days"},{"section":"5910","description":"IDR procedure — informal, no formal rules of evidence"},{"section":"5925","description":"ADR — mediation and arbitration for CID disputes"},{"section":"5930","description":"ADR — scope of disputes covered"},{"section":"5935","description":"ADR summary — must include in annual policy statement"},{"section":"5960","description":"Failure to participate in ADR — attorney fee consequences"},{"section":"5965","description":"Court may stay litigation and order ADR"}]', '["IDR_request","IDR_meeting_minutes","ADR_demand","mediation_agreement","arbitration_award","annual_policy_statement","attorney_fee_motion","ADR_completion_certificate","civil_complaint_HOA_dispute"]', '["california-real-estate-audit"]', 'California Civil Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — Construction / Contractor Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- Contractor State License Board
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_136', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 7000-7191 (Contractors State License Law)', 'BPC §§ 7000-7191', 'Contractors State License Law — Licensing Requirements', 'All persons performing construction work in California for projects valued at $500 or more (combined labor and materials) must hold a valid contractor''s license issued by the Contractors State License Board (CSLB). License classifications include Class A (General Engineering), Class B (General Building), and Class C (Specialty). Operating without a license is a misdemeanor and renders the contractor unable to maintain a lawsuit to collect compensation for the work. Contractor must include license number on all contracts, bids, and advertising.', '["License required for any construction work $500 or more (labor + materials)","Class A: General Engineering — highways, bridges, dams, utilities","Class B: General Building — structures, framing, roofing, concrete","Class C: Specialty — 42 specialty classifications (C-10 Electrical, C-36 Plumbing, etc.)","Unlicensed contractor: misdemeanor and cannot sue to collect payment (BPC § 7031)","License number required on all contracts, bids, business cards, advertising","Contractor bond: $25,000 qualifying individual bond required","Workers compensation insurance required if employees","10% down payment limit on home improvement contracts","4-year experience or education requirement for licensure","Continuing education not required but CSLB may require for discipline cases"]', '[{"section":"7026","description":"Definition of contractor — anyone who constructs for compensation"},{"section":"7028","description":"Unlicensed contracting — misdemeanor, criminal penalties"},{"section":"7031","description":"Unlicensed contractor cannot maintain action for compensation"},{"section":"7040-7065","description":"License classifications — A, B, C specialties"},{"section":"7068-7068.2","description":"Qualifying individual — experience and examination"},{"section":"7071.6","description":"Contractor bond — $25,000 requirement"},{"section":"7071.8","description":"Workers compensation insurance requirement"},{"section":"7090-7099.11","description":"Disciplinary proceedings — grounds and procedures"},{"section":"7100-7124.6","description":"Penalties — administrative, civil, criminal"},{"section":"7159","description":"Home improvement contract requirements — content and form"}]', '["contractor_license_verification","license_application","contractor_bond","workers_comp_certificate","construction_contract","home_improvement_contract","bid_proposal","CSLB_complaint","disciplinary_action","license_renewal"]', '["california-construction-compliance-audit"]', 'Contractors State License Board (CSLB)', 1, 1, datetime('now'), datetime('now'));

-- Mechanic's Lien Law
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_137', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 8400-8494 (Mechanic''s Lien Law)', 'CC §§ 8400-8494', 'Mechanic''s Lien Law — Construction Lien Rights and Procedures', 'Persons who furnish labor, materials, equipment, or services for improvement of real property have a lien right to secure payment. Preliminary 20-day notice required from subcontractors and suppliers (not direct contractors). Mechanic''s lien must be recorded within 90 days of completion (direct contractor) or 60 days after notice of completion is recorded. Lien claimant must file enforcement action within 90 days of recording the lien. Direct contractor must serve Stop Payment Notice if payment bond exists.', '["Preliminary 20-day notice required from subcontractors/suppliers (CC § 8200)","Direct contractor: lien must be recorded within 90 days of completion","Subcontractor/supplier: lien must be recorded within 60 days after notice of completion is recorded","If no notice of completion recorded: 90 days from actual completion for all claimants","Lien enforcement action must be filed within 90 days of recording lien","Lien must include: claimant name, amount, property description, owner name","Licensed contractor requirement: unlicensed contractor has no lien rights (BPC § 7031)","Stop payment notice available for bonded projects","Release of lien: conditional and unconditional waiver forms (CC § 8132-8138)","Lien priority: relates back to commencement of work on the project"]', '[{"section":"8200-8216","description":"Preliminary 20-day notice — required for subcontractors/suppliers"},{"section":"8400","description":"Mechanic''s lien right — who may claim"},{"section":"8412","description":"Recording deadline — 90 days from completion"},{"section":"8414","description":"Recording deadline after notice of completion — 60 days"},{"section":"8416","description":"Contents of lien claim — required information"},{"section":"8460","description":"Enforcement action — 90-day deadline to file lawsuit"},{"section":"8470","description":"Lis pendens required upon filing enforcement action"},{"section":"8480-8488","description":"Petition to release lien — expedited removal procedure"},{"section":"8132-8138","description":"Lien release forms — conditional and unconditional waivers"},{"section":"8490-8494","description":"Lien priorities and relation back"}]', '["preliminary_20_day_notice","mechanic_lien_claim","lien_release_waiver","notice_of_completion","notice_to_owner","stop_payment_notice","lien_enforcement_complaint","lis_pendens","petition_to_release_lien","conditional_waiver","unconditional_waiver"]', '["california-construction-compliance-audit"]', 'California Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Construction Defect — Right to Repair (SB 800)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_138', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 895-945.5 (SB 800 — Right to Repair Act)', 'CC §§ 895-945.5', 'Construction Defect — Right to Repair Act (SB 800)', 'Establishes functionality standards for residential construction and a prelitigation process for construction defect claims against builders of new residential units. Defines specific standards for various building components (foundations, soils, structural, plumbing, electrical, etc.) and sets statutory timeframes for different defect types (1-10 years depending on component). Builder has right to inspect and offer repair before homeowner can file suit. Applies to new residential construction sold on or after January 1, 2003.', '["Functionality standards defined for each building component (CC § 896)","Prelitigation notice required: homeowner must give builder written notice of defect","Builder has 14 days to acknowledge receipt","Builder has right to inspect within 14 days of acknowledgment","Builder has 30 days after inspection to offer repair or monetary settlement","Homeowner may reject offer and proceed with mediation","If mediation fails, homeowner may file civil action","Statute of limitations by component: 1 year (landscape), 2 years (plumbing/electrical), 4 years (fire protection), 5 years (structural), 10 years (foundation/structural integrity)","Builder may establish enhanced protection agreement (CC § 912)","Does not apply to condominium conversions or commercial construction"]', '[{"section":"895","description":"Legislative intent — standards and prelitigation procedures"},{"section":"896","description":"Functionality standards — component-by-component requirements"},{"section":"897","description":"Standards for original construction only — not remodeling"},{"section":"910-938","description":"Prelitigation procedures — notice, inspection, offer, response"},{"section":"910","description":"Homeowner notice to builder — initiating the process"},{"section":"916","description":"Builder inspection right — 14-day window"},{"section":"917-921","description":"Builder offer to repair — 30-day window"},{"section":"927","description":"Mediation requirement before filing suit"},{"section":"941","description":"Statute of limitations — by component type"},{"section":"942-945.5","description":"Evidence and proof requirements — comparative fault"}]', '["construction_defect_notice","prelitigation_demand","builder_inspection_report","repair_offer","homeowner_response","mediation_demand","construction_defect_complaint","expert_inspection_report","warranty_claim","enhanced_protection_agreement"]', '["california-construction-compliance-audit"]', 'California Civil Courts / CSLB', 1, 1, datetime('now'), datetime('now'));

-- Home Improvement Contract Requirements
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_139', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 7150-7168 (Home Improvement Contract Requirements)', 'BPC §§ 7150-7168', 'Home Improvement Contract Requirements — Consumer Protection', 'Prescribes mandatory content and form for home improvement contracts and service and repair contracts. Contract must be in writing for any job over $500. Must include contractor''s license number, start and completion dates, description of work, total price, payment schedule, and required statutory notices. Down payment limited to $1,000 or 10% of contract price (whichever is less). Owner has 3-day right to cancel for home solicitation sales. Violations are grounds for CSLB disciplinary action.', '["Contract required in writing for work over $500","Must include contractor name, address, license number, phone","Must include approximate start and completion dates","Must include description of work and materials to be used","Must include agreed contract price — lump sum or time and materials with cap","Down payment limit: $1,000 or 10% of contract price, whichever is less","Progress payments may not exceed value of work performed","Must include 3-day right to cancel notice for home solicitation sales","Must include change order procedures — written and signed","Must include mechanics lien warning notice","Contract must be signed by owner and contractor","Copy of signed contract provided to owner immediately","Finance terms must comply with TILA if applicable","Service/repair contracts: additional requirements for service calls"]', '[{"section":"7150","description":"Definitions — home improvement, home improvement contract"},{"section":"7151","description":"Service and repair contracts — separate requirements"},{"section":"7159","description":"Home improvement contract — mandatory content"},{"section":"7159.5","description":"Home improvement contracts — required notices and disclosures"},{"section":"7159.10","description":"Down payment limitation — $1,000 or 10%"},{"section":"7159.14","description":"Progress payment restrictions — value of work completed"},{"section":"7160","description":"Right to cancel — 3 business days for home solicitation"},{"section":"7163","description":"Change order requirements — written and signed"},{"section":"7164","description":"Swimming pool contracts — additional requirements"},{"section":"7168","description":"Violation consequences — grounds for discipline"}]', '["home_improvement_contract","service_and_repair_contract","change_order","cancellation_notice","down_payment_receipt","progress_payment_invoice","mechanics_lien_warning","completion_certificate","warranty_document","CSLB_complaint"]', '["california-construction-compliance-audit"]', 'Contractors State License Board (CSLB)', 1, 1, datetime('now'), datetime('now'));

-- Prevailing Wage — Public Works
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_140', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code §§ 1720-1784 (Prevailing Wage Law — Public Works)', 'LC §§ 1720-1784', 'Prevailing Wage Law — California Public Works Projects', 'Workers employed on public works projects (construction, alteration, demolition, installation, repair paid for in whole or part with public funds) must be paid not less than the prevailing rate of per diem wages as determined by the Director of Industrial Relations (DIR). Contractors and subcontractors must be registered with DIR. Certified payroll records required. Penalties for violations include forfeiture of up to $200 per worker per day, debarment, and criminal sanctions. Apprenticeship requirements apply.', '["Prevailing wage required for all public works projects over $1,000","Public works: construction paid for in whole or part with public funds","Contractor and subcontractor must register with DIR (LC § 1725.5)","Certified payroll records required — submitted to awarding body and DIR (LC § 1776)","Payroll records must be maintained for 3 years","Prevailing wage rates determined by DIR — published online","Workers must receive per diem wages including hourly rate, overtime, benefits","Apprenticeship requirements: contractors must employ apprentices (LC § 1777.5)","Penalty: up to $200/worker/day for prevailing wage violations","Penalty: up to $100/worker/day for failure to submit certified payroll","Debarment from public works for violations","Joint labor-compliance committee may monitor compliance","Awarding body must include prevailing wage requirements in bid documents"]', '[{"section":"1720","description":"Definition of public works — scope of coverage"},{"section":"1720.2-1720.4","description":"Expanded public works definitions — hauling, off-site work"},{"section":"1725.5","description":"Contractor registration with DIR — mandatory for public works"},{"section":"1770-1773.1","description":"Prevailing wage determinations by DIR"},{"section":"1774","description":"Obligation to pay not less than prevailing wage"},{"section":"1775","description":"Penalties — forfeiture for prevailing wage violations"},{"section":"1776","description":"Certified payroll records — submission and retention"},{"section":"1777.5","description":"Apprenticeship requirements — hiring ratios"},{"section":"1777.7","description":"Penalties for apprenticeship violations"},{"section":"1780-1784","description":"Criminal penalties for willful violations"}]', '["prevailing_wage_determination","certified_payroll_records","DIR_registration","public_works_contract","apprenticeship_standards","labor_compliance_report","wage_complaint","debarment_notice","bid_specification","payroll_audit","joint_labor_compliance_report"]', '["california-construction-compliance-audit"]', 'Department of Industrial Relations (DIR) / Division of Labor Standards Enforcement (DLSE)', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — Consumer Protection Standards
-- ═══════════════════════════════════════════════════════════════════════════

-- Consumer Legal Remedies Act (CLRA)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_141', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1750-1784 (Consumer Legal Remedies Act — CLRA)', 'CC §§ 1750-1784', 'Consumer Legal Remedies Act — Unfair and Deceptive Practices', 'Prohibits 27 enumerated unfair methods of competition and unfair or deceptive acts or practices in transactions for the sale of goods or services to consumers. Provides for actual damages, injunctive relief, restitution, punitive damages, and attorney fees. Consumer must send 30-day demand letter before filing for damages (not required for injunctive relief). CLRA claims cannot be waived — any waiver is void and unenforceable. Class actions permitted.', '["Prohibits 27 specific unfair or deceptive practices (CC § 1770)","Includes: passing off goods, misrepresenting source, bait and switch, false warranty","Includes: unconscionable price increases during emergency (added 2020)","30-day demand letter required before suing for damages (CC § 1782)","Demand letter not required for injunctive relief","Actual damages recoverable — economic and noneconomic","Attorney fees and costs to prevailing consumer plaintiff","Punitive damages available for willful violations","Class action authorized — no class action waiver enforceable","CLRA rights cannot be waived by contract — any waiver is void","Applies to goods AND services transactions with consumers","3-year statute of limitations","Senior citizen or disabled person: enhanced damages available"]', '[{"section":"1750","description":"Short title — Consumer Legal Remedies Act"},{"section":"1760","description":"Definitions — consumer, transaction, goods, services"},{"section":"1770","description":"27 prohibited unfair and deceptive acts or practices"},{"section":"1770(a)(1)","description":"Passing off goods or services as those of another"},{"section":"1770(a)(5)","description":"Representing goods of a particular standard when they are not"},{"section":"1770(a)(9)","description":"Advertising goods with intent not to sell as advertised"},{"section":"1770(a)(14)","description":"Misrepresenting that transaction involves consumer rights or obligations"},{"section":"1780","description":"Remedies — actual damages, injunction, restitution, punitive damages"},{"section":"1781","description":"Class actions — requirements and procedures"},{"section":"1782","description":"30-day demand letter prerequisite for damages"},{"section":"1784","description":"CLRA rights nonwaivable — waiver is void"}]', '["CLRA_demand_letter","CLRA_complaint","class_action_complaint","injunction_motion","restitution_claim","punitive_damages_claim","consumer_complaint","deceptive_practice_evidence","settlement_agreement","attorney_fee_motion"]', '["california-consumer-protection-audit"]', 'California AG / Private Enforcement / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Song-Beverly Consumer Warranty Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_142', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1790-1795.8 (Song-Beverly Consumer Warranty Act)', 'CC §§ 1790-1795.8', 'Song-Beverly Consumer Warranty Act — California Warranty Rights', 'California''s comprehensive consumer warranty statute. Every sale of consumer goods accompanied by manufacturer''s express warranty carries implied warranties of merchantability and fitness. If manufacturer or dealer cannot repair product after a reasonable number of attempts, consumer is entitled to replacement or refund (the "Lemon Law" for all consumer goods). Civil penalty of up to two times actual damages for willful violation. Buyer entitled to attorney fees if prevailing.', '["Implied warranty of merchantability applies to all consumer goods sales","Implied warranty cannot be disclaimed if express warranty given","Manufacturer must maintain service and repair facilities in California","Reasonable number of repair attempts required before replacement/refund","If unable to repair after reasonable attempts: buyer''s choice of replacement or refund","Refund includes sales tax, finance charges, incidental damages","Civil penalty: up to 2x actual damages for willful violation","Attorney fees to prevailing buyer","Service contract: separate from warranty, additional consumer protections","Retailer liability: if manufacturer unable to meet warranty obligations","Used goods: implied warranty may be limited to 30-90 days with disclosure"]', '[{"section":"1790","description":"Short title — Song-Beverly Consumer Warranty Act"},{"section":"1791","description":"Definitions — consumer goods, manufacturer, retail seller"},{"section":"1791.1","description":"Express warranties — creation and scope"},{"section":"1791.2","description":"Implied warranty of merchantability"},{"section":"1792","description":"Implied warranty attaches to all consumer goods sales"},{"section":"1793.2","description":"Manufacturer obligations — repair, replace, refund (Lemon Law)"},{"section":"1793.2(d)","description":"Replacement or refund election after reasonable repair attempts"},{"section":"1793.22","description":"Tanner Consumer Protection Act — new motor vehicle presumption"},{"section":"1794","description":"Buyer remedies — damages and civil penalty"},{"section":"1794(d)","description":"Attorney fees to prevailing buyer"},{"section":"1795.5","description":"Used goods — limited implied warranty"}]', '["warranty_claim","repair_order","repair_history","lemon_law_demand","replacement_request","refund_demand","consumer_complaint","attorney_fee_motion","civil_penalty_claim","warranty_disclosure","service_contract"]', '["california-consumer-protection-audit"]', 'California AG / DCA / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- CA Lemon Law — New Vehicle
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_143', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1793.2 (California Lemon Law — New Motor Vehicles)', 'CC § 1793.2', 'California Lemon Law — New Motor Vehicle Buyback/Replacement', 'Under Song-Beverly, if a manufacturer or its authorized dealer cannot conform a new motor vehicle to the applicable express warranty after a reasonable number of repair attempts, the manufacturer must either replace the vehicle or make restitution to the buyer. The Tanner Consumer Protection Act (CC § 1793.22) creates a presumption that a reasonable number of repair attempts has been exceeded if: (1) the same nonconformity has been subject to 4 or more repair attempts, or (2) the vehicle has been out of service for 30 or more calendar days. Applies within 18 months or 18,000 miles, whichever comes first.', '["Manufacturer must repair defect that substantially impairs use, value, or safety","Reasonable repair attempts presumed exceeded after 4 attempts for same defect","Reasonable repair attempts presumed exceeded after 30 days out of service","Presumption applies within 18 months or 18,000 miles (whichever first)","Buyer may elect replacement or restitution (refund)","Restitution: full purchase price less reasonable usage allowance","Usage allowance: mileage at first repair attempt ÷ 120,000 × purchase price","Manufacturer may deduct reasonable usage allowance from refund","Replacement must be substantially identical vehicle","Includes leased vehicles — lessor/lessee protections","Civil penalty up to 2x damages if manufacturer willfully fails to comply","Attorney fees to prevailing buyer","Manufacturer arbitration programs: nonbinding on consumer (CC § 1793.22(c))"]', '[{"section":"1793.2(a)","description":"Manufacturer duty to maintain service and repair facilities"},{"section":"1793.2(b)","description":"Manufacturer duty to repair within reasonable time"},{"section":"1793.2(d)(1)","description":"Replacement election — substantially identical vehicle"},{"section":"1793.2(d)(2)","description":"Restitution election — refund with usage allowance deduction"},{"section":"1793.2(e)(3)","description":"Usage allowance calculation formula"},{"section":"1793.22","description":"Tanner Consumer Protection Act — presumption of reasonable attempts"},{"section":"1793.22(b)","description":"4 repair attempts or 30 days out of service presumption"},{"section":"1793.22(c)","description":"Manufacturer arbitration — nonbinding on consumer"},{"section":"1793.22(e)(2)","description":"18 months/18,000 miles window for presumption"},{"section":"1794(c)","description":"Civil penalty up to 2x damages for willful noncompliance"}]', '["lemon_law_demand_letter","repair_order_history","vehicle_purchase_contract","manufacturer_warranty","buyback_offer","replacement_offer","restitution_calculation","arbitration_demand","civil_complaint_lemon_law","attorney_fee_petition","usage_allowance_calculation"]', '["california-consumer-protection-audit"]', 'California AG / DCA / Civil Courts / BAR (Bureau of Automotive Repair)', 1, 1, datetime('now'), datetime('now'));

-- CA Lemon Law — Used Vehicle
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_144', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1795.51 (California Lemon Law — Used Motor Vehicles)', 'CC § 1795.51', 'California Lemon Law — Used Motor Vehicle Warranty Protections', 'Dealers who sell used motor vehicles with an express warranty are subject to Song-Beverly Act obligations. If the dealer or its repair facility is unable to service or repair a used vehicle to conform to the applicable express warranty after a reasonable number of attempts, the buyer may return the vehicle for a full refund. Dealer-issued express warranties on used vehicles trigger implied warranty of merchantability that cannot be disclaimed. Buyer may also pursue CLRA claims for undisclosed defects.', '["Dealer-issued express warranty on used vehicle triggers Song-Beverly protections","Implied warranty of merchantability attaches when express warranty is given","Implied warranty duration: coextensive with express warranty, minimum 30 days, maximum 3 months","Reasonable number of repair attempts required before return/refund","Buyer entitled to refund if dealer cannot conform to express warranty","Refund includes purchase price, sales tax, license fees, registration","Dealer liable for incidental and consequential damages","Civil penalty up to 2x damages for willful noncompliance","Attorney fees to prevailing buyer","As-is sales: no implied warranty unless Buyer''s Guide defective or deceptive","Certified pre-owned programs: enhanced warranty obligations"]', '[{"section":"1795.5","description":"Used goods — implied warranty when express warranty given"},{"section":"1795.51","description":"Used motor vehicles — dealer warranty obligations"},{"section":"1795.5(c)","description":"Duration of implied warranty — 30 days to 3 months"},{"section":"1794","description":"Remedies — damages, refund, civil penalty"},{"section":"1794(d)","description":"Attorney fees to prevailing buyer"},{"section":"1795.5(b)","description":"Dealer obligation to repair, replace, or refund"}]', '["used_vehicle_warranty","repair_order_history","purchase_contract","buyers_guide","lemon_law_demand","refund_demand","consumer_complaint","civil_complaint","dealer_warranty_disclosure","vehicle_inspection_report"]', '["california-consumer-protection-audit"]', 'California AG / DCA / BAR / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Automatic Renewal / Subscription (ARL)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_145', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 17600-17606 (Automatic Renewal Law — ARL)', 'BPC §§ 17600-17606', 'California Automatic Renewal and Continuous Service Law', 'Regulates automatic renewal and continuous service offers to California consumers. Businesses must present automatic renewal terms clearly and conspicuously before the purchase. Must obtain affirmative consent to the automatic renewal terms. Must provide acknowledgment including cancellation policy. Consumer must be able to cancel online if they signed up online (amended 2022, effective July 1, 2022). Free trial to paid conversion requires affirmative consent. Violations are treated as unlawful business practices under UCL.', '["Automatic renewal terms must be presented clearly and conspicuously","Clear and conspicuous: terms must be in visual proximity to consent mechanism","Must obtain affirmative consent to automatic renewal offer terms","Must provide acknowledgment of automatic renewal terms and cancellation policy","Acknowledgment must be deliverable: email, text, or other electronic means","Cancellation must be available online if consumer signed up online (eff. July 2022)","Cancellation must be easy to find and use — no dark patterns","Free trial to paid: must obtain affirmative consent before charging","Must send reminder notice before free trial converts to paid subscription","Gift/promotional subscriptions: must notify before automatic renewal begins","Violation = unlawful business practice under Business and Professions Code § 17200","Consumer entitled to full refund if terms not properly disclosed"]', '[{"section":"17600","description":"Short title — Automatic Renewal Law"},{"section":"17601","description":"Definitions — automatic renewal, continuous service, consumer"},{"section":"17602(a)","description":"Clear and conspicuous disclosure of automatic renewal terms"},{"section":"17602(b)","description":"Affirmative consent required before charging"},{"section":"17602(c)","description":"Acknowledgment with cancellation policy required"},{"section":"17602(d)","description":"Online cancellation required if signed up online"},{"section":"17603","description":"Free trial to paid — affirmative consent and reminder"},{"section":"17604","description":"Violation deemed unlawful business practice"},{"section":"17605","description":"Intent — no limit on other consumer protection laws"}]', '["subscription_agreement","automatic_renewal_disclosure","cancellation_policy","consent_mechanism_screenshot","acknowledgment_email","cancellation_confirmation","refund_request","UCL_complaint","FTC_dark_patterns_analysis","free_trial_terms"]', '["california-consumer-protection-audit"]', 'California AG / District Attorneys / City Attorneys / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Gift Card / Gift Certificate
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_146', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1749.45-1749.6 (Gift Card and Gift Certificate Law)', 'CC §§ 1749.45-1749.6', 'California Gift Card and Gift Certificate Consumer Protections', 'California prohibits expiration dates on gift certificates and gift cards. No inactivity fees, dormancy fees, or service charges permitted on gift cards sold to consumers. Gift cards with a remaining balance of less than $10 must be redeemed for cash upon consumer request (the "$10 cash back" rule). Exceptions exist for promotional cards issued as part of loyalty programs if clearly marked. Federal CARD Act provides parallel protections but California law is more protective and is not preempted.', '["Gift certificates: no expiration date permitted","Gift cards: no expiration date permitted","No inactivity, dormancy, or service fees on gift cards","Cash back required for remaining balance under $10 upon consumer request","Cash back must be provided in cash (not store credit)","Exceptions: promotional/loyalty cards if clearly marked as such","Exceptions: cards given as charitable donations under certain conditions","Gift card must state if cash back is available and how to obtain it","Retailer bankruptcy: gift card holders are unsecured creditors","Federal CARD Act: no expiration for 5 years, no inactivity fees for 12 months — CA is more protective"]', '[{"section":"1749.45","description":"Definitions — gift certificate, gift card"},{"section":"1749.5(a)","description":"No expiration date on gift certificates or gift cards"},{"section":"1749.5(b)","description":"No service fees, inactivity fees, or dormancy fees"},{"section":"1749.5(b)(2)","description":"Cash back required for balance under $10"},{"section":"1749.5(c)","description":"Exceptions — promotional and loyalty cards"},{"section":"1749.5(d)","description":"Exceptions — charitable organizations"},{"section":"1749.6","description":"Disclosure requirements on gift card packaging"},{"section":"CARD Act § 915(b)","description":"Federal parallel — 5-year minimum, 12-month fee moratorium"}]', '["gift_card_policy","cash_back_policy","gift_card_disclosure","promotional_card_terms","consumer_complaint","restitution_claim","point_of_sale_compliance","gift_card_audit"]', '["california-consumer-protection-audit"]', 'California AG / DCA / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- California Telephone Consumer Protection
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_147', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 17590-17594 (California Restrictions on Unsolicited Commercial Calls)', 'BPC §§ 17590-17594', 'California Telephone Consumer Protection — Restrictions on Unsolicited Calls and Texts', 'Supplements the federal Telephone Consumer Protection Act (TCPA) with California-specific restrictions on unsolicited commercial telephone calls and text messages. Prohibits calls to numbers on the National Do Not Call Registry. Requires caller identification. Robocall restrictions apply to both voice and text. Business must honor consumer opt-out requests. California consumers have private right of action with statutory damages. Works in conjunction with federal TCPA 47 USC § 227.', '["Prohibits unsolicited commercial calls to numbers on Do Not Call Registry","Caller must transmit accurate caller ID information","No robocalls or auto-dialed calls without prior express consent","No unsolicited commercial text messages without prior express consent","Must honor consumer opt-out requests immediately","Must maintain internal do-not-call list for 10 years","Calling hours restricted: no calls before 8am or after 9pm","Must identify caller name, company, and purpose at beginning of call","Statutory damages for violations","Works with federal TCPA — California provides additional protections","Prior express written consent required for autodialed or prerecorded marketing calls","Exemptions: tax-exempt nonprofits, political campaigns, existing business relationship (limited)"]', '[{"section":"17590","description":"Legislative findings — consumer protection from unwanted calls"},{"section":"17591","description":"Definitions — unsolicited call, automatic dialing system"},{"section":"17592","description":"Prohibited practices — robocalls, DNC violations, caller ID spoofing"},{"section":"17593","description":"Enforcement — AG, DA, city attorneys, private right of action"},{"section":"17594","description":"Penalties and damages"},{"section":"TCPA 47 USC § 227","description":"Federal parallel — $500 per violation, trebled for willful"}]', '["do_not_call_policy","consent_records","opt_out_log","caller_ID_compliance","autodialer_consent_form","TCPA_complaint","consumer_complaint","call_log_audit","text_message_consent","internal_DNC_list"]', '["california-consumer-protection-audit"]', 'California AG / DA / FCC / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- CA Buyer's Guide Requirements (Used Vehicle)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_148', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Veh. Code § 11713.21 (Used Vehicle Buyer''s Guide Requirements)', 'Veh. Code § 11713.21', 'California Used Vehicle Buyer''s Guide — Dealer Disclosure Requirements', 'Licensed motor vehicle dealers must post a Buyer''s Guide on every used vehicle offered for sale. The Buyer''s Guide must disclose whether the vehicle is sold "As Is" or with a warranty, major defects that may occur in used vehicles, and a suggestion to have the vehicle inspected. California requires that the Buyer''s Guide be provided in English and Spanish if the sale was negotiated in Spanish. The Buyer''s Guide becomes part of the sales contract. Complements the FTC Used Car Rule (16 CFR Part 455).', '["Buyer''s Guide must be posted on every used vehicle offered for sale","Must state As Is or Warranty — and warranty terms if applicable","Must list major systems and defects that may occur","Must suggest pre-purchase independent inspection","Buyer''s Guide becomes part of sales contract upon sale","Must be provided in language of negotiation (Spanish if negotiated in Spanish)","FTC Used Car Rule (16 CFR 455) establishes federal baseline — California supplements","Dealer cannot disclaim implied warranties if Buyer''s Guide states warranty","Failure to comply is a violation of Vehicle Code and may constitute CLRA violation","Must include dealer name, address, and contact information","Must disclose if vehicle was previously used as rental, fleet, or livery"]', '[{"section":"Veh. Code 11713.21","description":"Buyer''s Guide posting and disclosure requirements"},{"section":"Veh. Code 11713.1","description":"Unlawful dealer acts — failure to disclose"},{"section":"16 CFR 455","description":"FTC Used Car Rule — federal Buyer''s Guide requirements"},{"section":"16 CFR 455.2","description":"Required content of Buyer''s Guide"},{"section":"16 CFR 455.3","description":"Buyer''s Guide as part of contract"},{"section":"CC 1795.51","description":"Used vehicle warranty obligations under Song-Beverly"}]', '["buyers_guide","purchase_contract","warranty_disclosure","vehicle_history_report","pre_sale_inspection","as_is_disclosure","dealer_compliance_audit","Spanish_language_buyers_guide","consumer_complaint","CLRA_demand"]', '["california-consumer-protection-audit"]', 'DMV / DCA / FTC / Civil Courts', 1, 1, datetime('now'), datetime('now'));

-- Government Tort Claims Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_149', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 810-996.6 (California Government Tort Claims Act)', 'GC §§ 810-996.6', 'California Government Tort Claims Act — Prerequisites to Suit Against Public Entity', 'Before filing a lawsuit against a California public entity or public employee (acting within scope of employment), the claimant must first file a Government Tort Claim with the relevant public entity. Claim must be filed within 6 months of the accrual of the cause of action for personal injury/property damage, or 1 year for other claims. If the claim is rejected or deemed rejected (no response within 45 days), claimant has 6 months to file suit. Failure to file a timely claim bars the lawsuit. Late claim relief available under limited circumstances.', '["Tort claim must be filed before suing any California public entity","6-month deadline for personal injury, death, and property damage claims","1-year deadline for all other claims (contract, inverse condemnation, etc.)","Claim must be presented to the entity''s governing body or designated person","Claim must include: claimant info, date/place/circumstances, description of injury, amount demanded","If amount exceeds $10,000: may state amount or indicate jurisdictional classification (limited/unlimited)","Entity has 45 days to respond — if no response, claim is deemed rejected","After rejection: 6-month deadline to file lawsuit","Late claim application: available within 1 year — must show excusable neglect (GC § 911.4)","Government Code § 946.6: petition court for relief from claim requirement if late claim denied","Public entity immunity: GC § 815 — no common law tort liability, only statutory liability","Dangerous condition of public property: GC §§ 830-840.6 — liability exception","Employee immunity: GC §§ 820-825.6 — scope of employment protections","Police/fire immunity: GC §§ 845-850.8 — limited duty exceptions"]', '[{"section":"810","description":"Short title — California Tort Claims Act"},{"section":"815","description":"Public entity not liable except as provided by statute"},{"section":"815.2","description":"Vicarious liability — entity liable for employee acts within scope"},{"section":"820","description":"Employee liability — same as private person"},{"section":"820.2","description":"Discretionary act immunity — policy decisions"},{"section":"830-840.6","description":"Dangerous condition of public property — liability standards"},{"section":"845","description":"Police protection — no duty to provide, immunity"},{"section":"900-915.4","description":"Claims presentation procedure — requirements and deadlines"},{"section":"910","description":"Required contents of tort claim"},{"section":"911.2","description":"Filing deadlines — 6 months personal injury, 1 year other"},{"section":"911.4-911.6","description":"Late claim relief — application within 1 year"},{"section":"912.4","description":"Entity response — 45 days, deemed rejected if no response"},{"section":"913","description":"Claimant notification of rejection — 6-month suit deadline"},{"section":"945.4","description":"No suit against public entity without prior claim presentation"},{"section":"946.6","description":"Court petition for relief from claim requirement"}]', '["government_tort_claim","claim_rejection_notice","late_claim_application","petition_for_relief_946.6","civil_complaint_public_entity","dangerous_condition_complaint","police_misconduct_claim","immunity_defense","notice_of_rejection","claim_acknowledgment","statute_of_limitations_analysis"]', '["california-consumer-protection-audit"]', 'Public Entity Governing Body / California Civil Courts', 1, 1, datetime('now'), datetime('now'));
